(function(){
'use strict';
const PERF={normalCap:150,normalCapHigh:185,farCheck:.32,drawMargin:130,partsLow:150,partsHigh:230,fxLow:55,fxHigh:90};
function isRiftRun(){return !!(window.S&&S.rift&&S.rift.active)}
function countAdds(){let n=0;if(!window.S||!S.enemies)return 0;for(const e of S.enemies)if(!e.boss&&!e.dead)n++;return n}
function perfCap(){if(!window.S)return PERF.normalCap;if(S.endless)return window.ENDLESS_MONSTER_CAP||100;if(isRiftRun())return 9999;let q=window.fxQuality||'low',base=q==='high'?PERF.normalCapHigh:PERF.normalCap;return Math.min(base+Math.floor((S.time||0)/90)*8,220)}
function edgeAhead(){let p=S.player,m=70,dx=p.vx||0,dy=p.vy||0,move=Math.hypot(dx,dy)>.25;if(move&&Math.random()<.7){let d=Math.hypot(dx,dy)||1,px=-dy/d,py=dx/d,dist=Math.max(W,H)*.62,side=rand(-Math.min(W,H)*.55,Math.min(W,H)*.55);return{x:clamp(p.x+dx/d*dist+px*side,32,WORLD_W-32),y:clamp(p.y+dy/d*dist+py*side,72,WORLD_H-32)}}let e=Math.floor(rand(0,4));return{x:e<2?rand(CAMX-m,CAMX+W+m):(e===2?CAMX-m:CAMX+W+m),y:e<2?(e===0?CAMY-m:CAMY+H+m):rand(CAMY-m,CAMY+H+m)}}
function recycleFarEnemies(){if(!S?.player||!S.enemies?.length)return;let p=S.player,limit=Math.max(W,H)*1.18+180,moved=0;for(const e of S.enemies){if(moved>=10)break;if(e.boss||e.dead||e.elite&&isRiftRun())continue;let dx=e.x-p.x,dy=e.y-p.y;if(Math.abs(dx)<limit&&Math.abs(dy)<limit)continue;let pos=edgeAhead();if(typeof safeSpawn==='function')pos=safeSpawn(pos,e.r+28);e.x=pos.x;e.y=pos.y;e.attackCd=Math.max(e.attackCd||0,.5);e.phase=rand(0,TAU);moved++}}
function trimRuntimeLists(){if(!S)return;let high=(window.fxQuality||'low')==='high',pm=high?PERF.partsHigh:PERF.partsLow,fm=high?PERF.fxHigh:PERF.fxLow;if(S.parts?.length>pm)S.parts.splice(0,S.parts.length-pm);if(S.artFx?.length>fm)S.artFx.splice(0,S.artFx.length-fm);if(S.enemyShots?.length>120)S.enemyShots.splice(0,S.enemyShots.length-120)}
function visible(e,extra=PERF.drawMargin){return e.x>CAMX-extra&&e.x<CAMX+W+extra&&e.y>CAMY-extra&&e.y<CAMY+H+extra}
function drawBar(e,y,c,w=4){ctx.fillStyle='rgba(0,0,0,.55)';ctx.fillRect(e.x-e.r,y,e.r*2,w);ctx.fillStyle=c;ctx.fillRect(e.x-e.r,y,e.r*2*clamp(e.hp/e.max,0,1),w)}
function drawEnemyStatus(e){if(e._thunderVuln>0){ctx.save();ctx.globalCompositeOperation='lighter';ctx.globalAlpha=.18+Math.sin(S.time*12)*.08;ctx.fillStyle='#fde047';ctx.shadowColor='#fde047';ctx.shadowBlur=16;ctx.beginPath();ctx.arc(e.x,e.y,e.r+8+Math.sin(S.time*8)*3,0,TAU);ctx.fill();ctx.restore()}if(e._abyssExecute){ctx.save();ctx.globalCompositeOperation='lighter';ctx.globalAlpha=.35;ctx.fillStyle='#a78bfa';ctx.shadowColor='#7c3aed';ctx.shadowBlur=28;ctx.beginPath();ctx.arc(e.x,e.y,e.r+12,0,TAU);ctx.fill();ctx.restore()}if(e._kamikaze){ctx.save();ctx.globalCompositeOperation='lighter';ctx.globalAlpha=.25+Math.sin(S.time*10)*.12;ctx.fillStyle='#fb7185';ctx.shadowColor='#e11d48';ctx.shadowBlur=14;ctx.beginPath();ctx.arc(e.x,e.y,e.r+6,0,TAU);ctx.fill();ctx.restore()}}
function buildGrid(){if(!S?.enemies)return null;let cell=160,stamp=S.time+'|'+S.enemies.length,g=S._enemyGrid;if(g&&g.stamp===stamp)return g;g={cell,stamp,map:new Map()};for(const e of S.enemies){if(e.dead)continue;let k=(e.x/cell|0)+','+(e.y/cell|0),a=g.map.get(k);if(a)a.push(e);else g.map.set(k,[e])}S._enemyGrid=g;return g}
function nearbyEnemies(x,y,r){let g=buildGrid();if(!g)return S?.enemies||[];let c=g.cell,out=[],seen=new Set(),x0=(x-r)/c|0,x1=(x+r)/c|0,y0=(y-r)/c|0,y1=(y+r)/c|0;for(let ix=x0;ix<=x1;ix++)for(let iy=y0;iy<=y1;iy++){let a=g.map.get(ix+','+iy);if(!a)continue;for(const e of a)if(!seen.has(e)){seen.add(e);out.push(e)}}return out}
function patchAreaDamage(){window.nearbyEnemies=nearbyEnemies;window.rangeDamage=function(kind,x,y,dmg,rad,slow=0){let hits=0,r2=rad*rad;for(const m of nearbyEnemies(x,y,rad+70)){let dx=m.x-x,dy=m.y-y,rr=rad+(m.r||0);if(dx*dx+dy*dy<rr*rr){dealDamage(m,dmg,true,modSkill(kind));if(slow)m.slow=Math.max(m.slow,slow);hits++}}return hits};window.lightBurstAt=function(kind,x,y,dmg,rad,slow=0,color='#facc15',size=100,life=.45,drawKind=kind){let hits=window.rangeDamage(kind,x,y,dmg,rad,slow);S.artFx.push({x,y,i:0,type:drawKind,color,life,max:life,size,kind:drawKind});if(kind!=='aura')sfx(kind==='voidRift'?'rift':kind==='poison'||kind==='sand'?'poison':kind==='blood'||kind==='bloodScythe'?'boom':kind==='deathWaltz'||kind==='soulReaper'?'slash':kind==='crystal'||kind==='meteor'?'boom':'holy');return hits};window.burstAt=function(kind,x,y,dmg,rad,slow=0,color='#facc15',size=100,life=.55){let hits=window.rangeDamage(kind,x,y,dmg,rad,slow);S.artFx.push({x,y,i:0,type:kind,color,life,max:life,size,kind});for(let n=0;n<Math.min(8,Math.max(3,Math.floor(12-fxScale()*4)));n++)S.parts.push({x,y,vx:rand(-70,70),vy:rand(-70,70),life:rand(.18,.45),max:.45,a:1,c:color});if(kind!=='aura')sfx(kind==='voidRift'?'rift':kind==='poison'||kind==='sand'?'poison':kind==='blood'||kind==='bloodScythe'?'boom':kind==='deathWaltz'||kind==='soulReaper'?'slash':kind==='crystal'||kind==='meteor'?'boom':'holy');return hits}}
function patchTargets(){window.activeAdds=countAdds;window.targetEnemy=function(p){let boss=null,bd=1e9,best=null,bt=-1,bd2=1e9,near=null,nd=1e9;for(const e of nearbyEnemies(p.x,p.y,560)){let d=Math.hypot(e.x-p.x,e.y-p.y);if(e.boss&&d<bd){boss=e;bd=d}if(d<nd){near=e;nd=d}if(!e.boss&&d<520){let t=threatScore(e);if(t>bt||t===bt&&d<bd2){best=e;bt=t;bd2=d}}}return boss||best||near};
window.targetForSkill=function(id){let p=S.player,cfg=SKILL_RANGE[id]||{range:999,ideal:260},boss=null,best=null,bs=1e9,bt=-1;for(const e of nearbyEnemies(p.x,p.y,cfg.range+90)){let d=Math.hypot(e.x-p.x,e.y-p.y);if(d>cfg.range+e.r)continue;if(e.boss&&!boss)boss=e;if(cfg.kind==='近战'){let s=Math.abs(d-cfg.ideal);if(s<bs){best=e;bs=s}}else{let t=threatScore(e),s=Math.abs(d-cfg.ideal);if(t>bt||t===bt&&s<bs){best=e;bt=t;bs=s}}}return boss||best};
window.densestEnemyPoint=function(){if(!S?.enemies?.length)return null;let cell=190,best=null,bs=0,bx=0,by=0,map=new Map();for(const e of S.enemies){if(e.boss)continue;let k=(e.x/cell|0)+','+(e.y/cell|0),g=map.get(k);if(!g)map.set(k,g={n:0,x:0,y:0});g.n++;g.x+=e.x;g.y+=e.y}for(const g of map.values())if(g.n>bs){bs=g.n;bx=g.x/g.n;by=g.y/g.n;best=g}return best?{x:bx,y:by,score:bs}:null}}
function patchSpawn(){let oldCount=window.spawnCount,oldSpawn=window.spawnEnemy;window.spawnCount=function(){let n=oldCount?oldCount():1;if(!S||isRiftRun())return n;return Math.min(n,Math.max(0,perfCap()-countAdds()))};window.spawnEnemy=function(boss=false,forced=null){if(!boss&&S&&!isRiftRun()&&countAdds()>=perfCap())return false;return oldSpawn?oldSpawn(boss,forced):false}}
function patchUpdate(){let old=window.updateObjs;window.updateObjs=function(dt){if(old)old(dt);if(S)S._enemyGrid=null;S._perfFarAt=(S._perfFarAt||0)-dt;if(S._perfFarAt<=0){S._perfFarAt=PERF.farCheck;recycleFarEnemies();S._enemyGrid=null}trimRuntimeLists()}}
function patchDraw(){window.drawEnemies=function(){let total=S.enemies.length,showBars=total<90;for(const e of S.enemies){if(!visible(e,e.boss?220:PERF.drawMargin))continue;let base=e.boss?150:e.type==='slime'?(e.mini?34:58):e.type==='eye'||e.type==='healer'?48:e.type==='shield'||e.type==='charger'?50:42,scale=e.boss?1:e.type==='guardian'?1.12:e.type==='wraith'?1.08:e.elite&&e.type!=='shield'?1.06:1,sz=base*scale;if(e.boss){let breath=Math.sin(S.time*2)*.025;drawSheet(imgs[e.img||'boss'],e.x,e.y,sz,Math.floor((e.anim||0)*.7)%4,0,1+breath,1-breath)}else{let frame=Math.floor(e.anim||0)%4,bob=Math.sin((e.anim||0)*TAU/4)*1.4,stretch=e.type==='slime'?Math.sin((e.anim||0)*TAU/4)*.06:0;drawSheet(imgs[e.img||'imp'],e.x,e.y+bob,sz,frame,0,1+stretch,1-stretch)}let needBar=e.boss||e.elite||showBars||e.hit>0||e.hp<e.max*.92;if(needBar){drawBar(e,e.y-e.r-10,e.elite?'#a855f7':'#ef4444');if(e.shield>0){ctx.fillStyle='rgba(15,23,42,.85)';ctx.fillRect(e.x-e.r,e.y-e.r-17,e.r*2,4);ctx.fillStyle='#60a5fa';ctx.fillRect(e.x-e.r,e.y-e.r-17,e.r*2*clamp(e.shield/3,0,1),4)}}if(e.boss||e.elite||total<120)drawEnemyStatus(e)}}}
function patchAll(){patchAreaDamage();patchTargets();patchSpawn();patchUpdate();patchDraw();console.info('性能补丁已启用：怪物上限、远距重投放、绘制裁剪、技能碰撞网格')}
patchAll();
})();
